// Extract data dari webhook
const input = $input.first().json;

const jobId = input.jobId;
const clips = input.clips || [];
const metadata = input.metadata || {};
const callbackUrl = input.callbackUrl;

// Siapkan items untuk setiap clip
const items = clips.map((clip, index) => ({
  json: {
    jobId,
    clipIndex: index,
    filePath: clip.filePath,
    relativePath: clip.relativePath,
    fileName: clip.fileName || `clip-${index + 1}.mp4`,
    caption: clip.caption,
    hashtags: clip.hashtags,
    score: clip.score,
    durationSeconds: clip.durationSeconds,
    callbackUrl,
    metadata
  }
}));

return items;

// Kumpulkan hasil upload
const items = $input.all();

const results = items.map(item => {
  const data = item.json;
  return {
    clipIndex: data.clipIndex ?? 0,
    driveUrl: data.webViewLink || data.webContentLink || '',
    driveFileId: data.id || '',
    fileName: data.name || ''
  };
});

// Ambil jobId dan callbackUrl dari item pertama
const first = items[0]?.json || {};

return [{
  json: {
    jobId: first.jobId,
    success: true,
    results,
    callbackUrl: first.callbackUrl
  }
}];
